<div class="d-flex justify-content-between mb-2"><h1 class="h5">Suscripciones</h1><form><select name="estado" class="form-select form-select-sm" onchange="this.form.submit()"><option value="">Todos</option><?php foreach(['activa','pendiente','por_vencer','vencida','suspendida','cancelada'] as $est): ?><option value="<?= $est ?>" <?= $estado===$est?'selected':'' ?>><?= $est ?></option><?php endforeach; ?></select></form></div><table class="table table-sm"><thead><tr><th>Empresa</th><th>Plan</th><th>Inicio</th><th>Vence</th><th>Días</th><th>Estado</th><th>Acción</th></tr></thead><tbody><?php foreach($suscripciones as $s): ?><tr><td><?= e($s['empresa']) ?></td><td><?= e($s['plan']) ?></td><td><?= e($s['fecha_inicio']) ?></td><td><?= e($s['fecha_vencimiento']) ?></td><td><?= e((string)$s['dias_restantes']) ?></td><td><span class="badge text-bg-<?= $s['estado']==='activa'?'success':'secondary' ?>"><?= e($s['estado']) ?></span></td><td><form method="POST" action="/admin/suscripciones/ver/<?= $s['id'] ?>" class="d-flex gap-1"><?= csrf_campo() ?><select class="form-select form-select-sm" name="estado"><option>activa</option><option>por_vencer</option><option>vencida</option><option>suspendida</option><option>cancelada</option></select><input name="observaciones" class="form-control form-control-sm" placeholder="Observación"><button class="btn btn-sm btn-outline-primary">Actualizar</button></form></td></tr><?php endforeach; ?></tbody></table>
